import{_ as t,o as e,c as r,ai as l}from"./chunks/framework.DjxHwWNk.js";const b=JSON.parse('{"title":"УрГАХУ, корпус «Пряник»","description":"Легендарная репетиционная база свердловского андеграунда, связанная с «Наутилусом Помпилиус», «Урфин Джюс» и ранним кино Алексея Балабанова.","frontmatter":{"title":"УрГАХУ, корпус «Пряник»","description":"Легендарная репетиционная база свердловского андеграунда, связанная с «Наутилусом Помпилиус», «Урфин Джюс» и ранним кино Алексея Балабанова.","outline":"deep"},"headers":[],"relativePath":"places/pryanik-urgahu.md","filePath":"places/pryanik-urgahu.md"}'),d={name:"places/pryanik-urgahu.md"};function s(i,a,o,n,h,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="ургаху-корпус-«пряник»" tabindex="-1">УрГАХУ, корпус «Пряник» <a class="header-anchor" href="#ургаху-корпус-«пряник»" aria-label="Permalink to “УрГАХУ, корпус «Пряник»”">​</a></h1><p><strong>УрГАХУ, корпус «Пряник»</strong> — одно из культовых мест свердловского андеграунда. Здание на улице Толмачёва известно не только своей необычной архитектурой, но и подвальными помещениями, где в 1980-е годы репетировали ключевые группы уральского рока.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, ул. Толмачёва, 24</li><li><strong>Период ключевого значения:</strong> 1980-е годы</li><li><strong>Главная роль:</strong> подвальная репетиционная база свердловского андеграунда</li><li><strong>Связанные группы:</strong> «Наутилус Помпилиус», «Урфин Джюс»</li><li><strong>Статус сегодня:</strong> действующий учебный корпус УрГАХУ</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>«Пряник» важен как пространство, где уральский рок существовал в своём естественном андеграундном виде: не на официальной сцене, а в подвалах, среди сырости, плохой акустики, самодельной аппаратуры и постоянного поиска собственного звучания.</p><p>Если ДК имени Свердлова стал официальной колыбелью Свердловского рок-клуба, то «Пряник» показывает другую сторону этой истории — неформальную, подвальную и экспериментальную. Здесь музыканты оттачивали материал, искали аранжировки и формировали тот самый звук, который позже выйдет на большие сцены.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Здание на улице Толмачёва, 24 известно в Екатеринбурге под неофициальным названием <strong>«Пряник»</strong>. Это один из корпусов Уральского государственного архитектурно-художественного университета. Своё прозвище здание получило благодаря характерной форме и декоративным элементам фасада, которые напоминают пряничный декор.</p><p>В историю уральского рока «Пряник» вошёл прежде всего благодаря своим подвальным помещениям. В 1980-е годы они стали репетиционной базой для нескольких важных групп свердловского андеграунда. Именно здесь репетировали <strong>«Наутилус Помпилиус»</strong> и <strong>«Урфин Джюс»</strong>.</p><p>По воспоминаниям очевидцев, условия были далеки от идеальных: подвалы были тесными и сырыми, а акустика оставляла желать лучшего. Но именно такая среда во многом соответствовала духу андеграунда — музыканты работали не благодаря комфорту, а вопреки ему. Здесь рождались первые аранжировки, отрабатывались концертные программы и формировались идеи, которые позже станут частью истории русского рока.</p><p>С «Пряником» связана и одна из городских легенд уральского рока. По рассказам, через музыкальную аппаратуру иногда случайно перехватывались частоты ближайшего отделения милиции. Во время репетиций в колонках могли прорываться переговоры патрулей. Эта история стала частью мифологии свердловского андеграунда и символом странного соседства рок-культуры и официальной советской действительности.</p><p>Здание также связано с ранним кино Алексея Балабанова. Режиссёр использовал подвалы и коридоры «Пряника» для съёмок эпизодов своего раннего фильма <strong>«Раньше было другое время»</strong>. Благодаря этому место оказалось важным не только для музыкальной, но и для кинематографической истории Екатеринбурга.</p><p>В 1990-е и 2000-е годы корпус продолжал использоваться университетом, а подвальные помещения постепенно утратили прежнюю репетиционную функцию. Тем не менее память о «Прянике» как о точке свердловского андеграунда сохранилась среди музыкантов, исследователей и поклонников уральского рока.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, ул. Толмачёва, 24.</p><p>Здание расположено в центральной части Екатеринбурга и удобно включается в пешие маршруты по рок-местам города.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/vyacheslav-butusov.html">Вячеслав Бутусов</a></td><td>Репетировал здесь в составе «Наутилуса Помпилиус»</td></tr><tr><td><a href="/Knowledge-Base/people/alexey-balabanov.html">Алексей Балабанов</a></td><td>Снимал здесь эпизоды своих ранних фильмов</td></tr><tr><td>Музыканты группы «Урфин Джюс»</td><td>Репетировали в подвальных помещениях здания</td></tr><tr><td>Студенты и участники свердловского андеграунда</td><td>Формировали творческую среду вокруг здания и его подвалов</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><ul><li><a href="/Knowledge-Base/bands/nautilus-pompilius.html">Наутилус Помпилиус</a></li><li><a href="/Knowledge-Base/bands/urfin-dzhus.html">Урфин Джюс</a></li></ul><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня здание продолжает использоваться как учебный корпус УрГАХУ. В нём располагаются аудитории, мастерские и другие университетские пространства.</p><p>Подвалы, где проходили легендарные репетиции, в настоящее время частично заброшены или используются для хозяйственных нужд. Несмотря на это, «Пряник» остаётся важной точкой памяти для тех, кто интересуется историей уральского рока и свердловского андеграунда.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Здание является действующим университетским корпусом, поэтому доступ внутрь и особенно в подвальные помещения может быть ограничен. Для маршрута это место лучше рассматривать как внешнюю точку с историческим комментарием.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока «Пряник» планируется включить в туристические маршруты по рок-местам Екатеринбурга как одну из главных репетиционных точек свердловского андеграунда.</p><p>Также в материалах проекта указана возможная установка информационной таблички. Она должна рассказать о подвальных репетициях, связи здания с «Наутилусом Помпилиус», «Урфин Джюс» и легенде о перехвате милицейских частот.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Включение «Пряника» в экскурсионные маршруты по рок-местам Екатеринбурга</td></tr><tr><td>2026 год</td><td>Возможная установка информационной таблички на здании</td></tr><tr><td>2026 год</td><td>Экскурсионные рассказы о подвальных репетициях и свердловском андеграунде</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>«Пряник» удобно включать в маршрут по центральным и студенческим местам уральского рока. Его можно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li><li><a href="/Knowledge-Base/places/urfu-rtf.html">УрФУ, Радиофак / РТФ УПИ</a></li><li><a href="/Knowledge-Base/places/bashlachev-house.html">Дом Александра Башлачёва</a></li></ul>',32)])])}const g=t(d,[["render",s]]);export{b as __pageData,g as default};
